using UnityEngine;

/// <summary>
/// O estado de reação actual de um NPC é (ou não é) "state" (ver
/// Action_SetReactionState).
/// </summary>
[System.Serializable]
public class Condition_NpcReactionState : NpcCondition
{
    public NpcReactionState state = NpcReactionState.Idle;

    [Tooltip("true = condição cumpre-se quando o estado É este; false = quando NÃO é.")]
    public bool mustMatch = true;

    [Tooltip("ID de outro NPC (Etapa 8 — ver \"Npc Id\" no NpcController desse NPC) cujo estado de reação é verificado. Vazio = este próprio NPC. Necessário para usar esta condição fora do contexto de um NPC (ex: MusicZone), onde \"este próprio NPC\" não existe — nesse caso, sem um ID definido a condição nunca se cumpre.")]
    public string targetNpcId;

    public override bool Evaluate(NpcController npc)
    {
        NpcController target = NpcController.FindById(targetNpcId);
        if (target == null) target = npc;
        if (target == null) return false;

        return (target.ReactionState == state) == mustMatch;
    }
}

/// <summary>
/// Um NPC — este, outro via "otherNpc"/"otherNpcId", ou, fora do contexto de um
/// NPC (ex: MusicZone), apenas via "otherNpcId" — está actualmente
/// visível/activo (ver NpcController.IsVisible, "visibilityConditions" e
/// Action_SetNpcVisible). Útil para condicionar o evento de um NPC ao estado de
/// visibilidade de outro (ex: NPC B só fala depois de NPC A ter aparecido), ou
/// para uma MusicZone só tocar enquanto um NPC estiver visível.
/// </summary>
[System.Serializable]
public class Condition_NpcVisible : NpcCondition
{
    [Tooltip("Vazio = este próprio NPC (ver \"otherNpcId\" abaixo para referenciar por ID, incluindo fora do contexto de um NPC).")]
    public NpcController otherNpc;

    [Tooltip("ID de outro NPC (Etapa 8 — ver \"Npc Id\" no NpcController desse NPC). Se definido e encontrado, tem prioridade sobre \"otherNpc\".")]
    public string otherNpcId;

    [Tooltip("true = condição cumpre-se se ESTIVER visível; false = se NÃO estiver.")]
    public bool mustBeVisible = true;

    public override bool Evaluate(NpcController npc)
    {
        NpcController target = NpcController.FindById(otherNpcId);
        if (target == null) target = otherNpc != null ? otherNpc : npc;
        if (target == null) return false;

        return target.IsVisible == mustBeVisible;
    }
}
